//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Run bidirectional, language, and direction properties"
//!
//! Each `#[test]` encodes a behavioural constraint mined from ECMA-376 /
//! ISO/IEC 29500 / MS-OI29500 about the run-level bidirectional containers
//! (`w:bdo`, `w:dir`), the run language triple (`w:lang` val/eastAsia/bidi),
//! and the proofing-suppression toggle (`w:noProof`).
//!
//! A FAILING assertion here is NOT a flaky test to silence: it encodes a real
//! Word-compliance GAP in the stemma engine. The expected value is what a
//! conforming consumer (Word) does; if stemma diverges, fix stemma (or, if the
//! rule is genuinely "what Word writes on save", treat it as an oracle
//! question), never weaken the assertion.
//!
//! Methodology note (consumption vs. save): stemma round-trips untouched
//! content byte-verbatim, so re-serialized XML of an unedited document reflects
//! stemma's preservation contract, NOT Word's normalization. These specs are
//! all consumption/validity rules, so they assert on the READ side
//! (`read_accepted()` / `read_rejected()` text) and on `validate()`
//! (opens-clean), never on re-serialized XML.

use std::io::{Read, Write};

use stemma::api::{Document, validate};

// ─── Prelude: minimal .docx plumbing ────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is the inner content of
/// `<w:body>…</w:body>` (paragraphs, sectPr, …). `extra_parts` is a list of
/// `(part_path, xml)` pairs (e.g. `("word/styles.xml", "…")`); each gets a
/// content-type override.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type override for each extra part, keyed by file name.
    let mut overrides = String::new();
    for (path, _) in extra_parts {
        let content_type = match *path {
            "word/styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "word/numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!("make_docx: no known content-type for extra part {other}"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{path}" ContentType="{content_type}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    let mut buf = Vec::new();
    {
        use zip::write::FileOptions;
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (path, xml) in extra_parts {
            zip.start_file(*path, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip and return the contents of `word/document.xml`.
#[allow(dead_code)]
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut out = String::new();
    file.read_to_string(&mut out).expect("read document.xml");
    out
}

/// Parse → serialize (with default export options) → return re-serialized
/// `word/document.xml`.
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc
        .serialize(&stemma::ExportOptions::default())
        .expect("serialize");
    document_xml_of(&out)
}

/// True iff `validate` reports no errors (opens clean).
fn opens_clean(bytes: &[u8]) -> (bool, String) {
    let report = validate(bytes);
    let detail = report
        .issues
        .iter()
        .map(|i| format!("[{:?}] {}", i.code, i.message))
        .collect::<Vec<_>>()
        .join("; ");
    (report.ok, detail)
}

fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
        .trim()
        .to_string()
}

fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
        .trim()
        .to_string()
}

