#[test]
fn bdo_override_wrapper_is_display_only_not_a_revision() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">part number: </w:t></w:r><w:bdo w:val="rtl"><w:r><w:t>ad-326D-FG</w:t></w:r></w:bdo></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b),
        "part number: ad-326D-FG",
        "§17.3.2.3 (ECMA-376 / ISO 29500-1): bdo is a display-only override equivalent to LRO/RLO control chars; it is not a tracked change, so accept-all yields the logical storage text unreversed."
    );
    assert_eq!(
        reject_text(&b),
        "part number: ad-326D-FG",
        "§17.3.2.3 (ECMA-376 / ISO 29500-1): bdo carries no revision; reject-all reproduces the same logical text (no insertion/deletion to undo)."
    );
}

