/// §17.3.2.3 (CT_BdoContentRun): when an edit elsewhere in the document forces
/// the body through the model-rebuild serializer (not the verbatim-bytes path),
/// a `w:bdo` direction wrapper must be re-emitted as ONE element nesting its
/// content — `<w:bdo>…runs…</w:bdo>` — not decomposed into two empty wrappers
/// with the runs flattened between them. The latter would strip the direction
/// override off the content and emit bogus empty wrappers. The wrapped run's
/// text must survive, and the document must still open clean.
///
/// This asserts on the rebuild path specifically (a tracked edit in a *separate*
/// paragraph), which the verbatim-preservation specs above do not exercise.
#[test]
fn bdo_wrapper_renests_on_model_rebuild_path() {
    use stemma::{DocxRuntime, ExportMode, SimpleRuntime, TransactionMeta};
    let before = make_docx(
        r#"<w:p><w:bdo w:val="rtl"><w:r><w:t>ABC123</w:t></w:r></w:bdo></w:p><w:p><w:r><w:t>edit me</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    let after = make_docx(
        r#"<w:p><w:bdo w:val="rtl"><w:r><w:t>ABC123</w:t></w:r></w:bdo></w:p><w:p><w:r><w:t>edited!</w:t></w:r></w:p><w:sectPr/>"#,
        &[],
    );
    let rt = SimpleRuntime::new();
    let ib = rt.import_docx(&before).expect("import before");
    let ia = rt.import_docx(&after).expect("import after");
    let meta = TransactionMeta {
        author: "bidi-spec".into(),
        reason: None,
        timestamp_utc: Some("2025-01-15T10:30:00Z".into()),
    };
    let applied = rt
        .diff_and_redline(&ib.doc_handle, &ia.doc_handle, meta)
        .expect("diff_and_redline");
    assert!(applied.applied, "the text edit should produce a redline");
    let out = rt
        .export_docx(&ib.doc_handle, ExportMode::Redline)
        .expect("export redline");
    let xml = document_xml_of(&out);

    // Exactly one bdo element, re-nested (not two empty bracket markers).
    assert_eq!(
        xml.matches("<w:bdo").count(),
        1,
        "§17.3.2.3: the model-rebuild path must re-nest the bdo wrapper into a \
         single element, not emit two empty markers. document.xml:\n{xml}"
    );
    assert!(
        xml.contains("ABC123"),
        "§17.3.2.3: the wrapped run text must survive the rebuild. \
         document.xml:\n{xml}"
    );
    let report = validate(&out);
    assert!(
        report.ok && report.issues.is_empty(),
        "§17.3.2.3: the rebuilt document with a re-nested bdo must open clean. \
         validate: ok={} issues={:?}",
        report.ok,
        report
            .issues
            .iter()
            .map(|i| format!("{:?}: {}", i.code, i.message))
            .collect::<Vec<_>>()
    );
}

/// §17.3.2.3 + §17.3.2.8: a direction wrapper nested inside another (here a
/// w:dir embedding inside a w:bdo override — the meaningful mixed-direction
/// shape) must ALSO re-nest on the model-rebuild path. The outer fold pulls the
/// inner pair of empty markers into the outer wrapper's children, so the
/// re-nest pass must recurse into the folded content — otherwise the inner
/// wrapper stays as two empty siblings and its direction embedding is lost.
#[test]
fn nested_direction_wrapper_renests_on_model_rebuild_path() {
    use stemma::{DocxRuntime, ExportMode, SimpleRuntime, TransactionMeta};
    let body_before = r#"<w:p><w:bdo w:val="rtl"><w:r><w:t>AAA</w:t></w:r><w:dir w:val="ltr"><w:r><w:t>BBB</w:t></w:r></w:dir><w:r><w:t>CCC</w:t></w:r></w:bdo></w:p><w:p><w:r><w:t>edit me</w:t></w:r></w:p><w:sectPr/>"#;
    let body_after = r#"<w:p><w:bdo w:val="rtl"><w:r><w:t>AAA</w:t></w:r><w:dir w:val="ltr"><w:r><w:t>BBB</w:t></w:r></w:dir><w:r><w:t>CCC</w:t></w:r></w:bdo></w:p><w:p><w:r><w:t>edited!</w:t></w:r></w:p><w:sectPr/>"#;
    let before = make_docx(body_before, &[]);
    let after = make_docx(body_after, &[]);
    let rt = SimpleRuntime::new();
    let ib = rt.import_docx(&before).expect("import before");
    let ia = rt.import_docx(&after).expect("import after");
    let meta = TransactionMeta {
        author: "bidi-spec".into(),
        reason: None,
        timestamp_utc: Some("2025-01-15T10:30:00Z".into()),
    };
    let applied = rt
        .diff_and_redline(&ib.doc_handle, &ia.doc_handle, meta)
        .expect("diff_and_redline");
    assert!(applied.applied, "the text edit should produce a redline");
    let out = rt
        .export_docx(&ib.doc_handle, ExportMode::Redline)
        .expect("export redline");
    let xml = document_xml_of(&out);

    // One bdo, one dir — each re-nested into a single populated element.
    assert_eq!(
        xml.matches("<w:bdo").count(),
        1,
        "outer bdo must re-nest into one element. document.xml:\n{xml}"
    );
    assert_eq!(
        xml.matches("<w:dir").count(),
        1,
        "inner dir must re-nest into one element (not remain a pair of empty \
         markers inside the folded bdo). document.xml:\n{xml}"
    );
    // The inner dir must actually CONTAIN its run — an empty <w:dir/> pair
    // would still satisfy the count if one half were dropped.
    assert!(
        xml.contains("<w:dir w:val=\"ltr\"><w:r><w:t>BBB</w:t></w:r></w:dir>"),
        "the inner dir embedding must wrap its run content after re-nesting. \
         document.xml:\n{xml}"
    );
    assert!(
        xml.contains("AAA") && xml.contains("CCC"),
        "outer wrapper content before/after the nested dir must survive. \
         document.xml:\n{xml}"
    );
    let report = validate(&out);
    assert!(
        report.ok && report.issues.is_empty(),
        "the rebuilt document with nested re-nested wrappers must open clean. \
         validate: ok={} issues={:?}",
        report.ok,
        report
            .issues
            .iter()
            .map(|i| format!("{:?}: {}", i.code, i.message))
            .collect::<Vec<_>>()
    );
}

// ─── Round-trip fidelity (hermetic) ─────────────────────────────────────────
// (The Word-oracle gold check for the rebuild path lives in the held-out
// real-Word conformance tier.)

/// Round-trip fidelity for nested/adjacent bdo/dir wrappers. The transparent
/// descent reconstructs the wrappers on serialize by pairing the empty
/// start/end markers; these are the ambiguous cases (byte-identical nested
/// markers, adjacent same-name, and deep bdo>dir>bdo nesting) where a naive
/// pairing would mis-nest or drop a level. Each must re-serialize verbatim AND
/// keep the inner text readable (display-only wrappers, §17.3.2.3/§17.3.2.8).
#[test]
fn bdo_dir_nested_and_adjacent_wrappers_roundtrip_verbatim() {
    // Nested with IDENTICAL w:val — start/end markers are byte-identical.
    let b1 = make_docx(
        r#"<w:p><w:bdo w:val="rtl"><w:bdo w:val="rtl"><w:r><w:t>X</w:t></w:r></w:bdo></w:bdo></w:p><w:sectPr/>"#,
        &[],
    );
    assert!(
        reserialize(&b1).contains(
            r#"<w:bdo w:val="rtl"><w:bdo w:val="rtl"><w:r><w:t>X</w:t></w:r></w:bdo></w:bdo>"#
        ),
        "nested identical-val bdo must round-trip verbatim: {}",
        reserialize(&b1)
    );
    assert_eq!(accept_text(&b1), "X");

    // Two ADJACENT same-name wrappers.
    let b2 = make_docx(
        r#"<w:p><w:bdo w:val="rtl"><w:r><w:t>A</w:t></w:r></w:bdo><w:bdo w:val="rtl"><w:r><w:t>B</w:t></w:r></w:bdo></w:p><w:sectPr/>"#,
        &[],
    );
    assert!(
        reserialize(&b2).contains(
            r#"<w:bdo w:val="rtl"><w:r><w:t>A</w:t></w:r></w:bdo><w:bdo w:val="rtl"><w:r><w:t>B</w:t></w:r></w:bdo>"#
        ),
        "adjacent same-name bdo must round-trip verbatim: {}",
        reserialize(&b2)
    );
    assert_eq!(accept_text(&b2), "AB");

    // DEEP mixed nesting bdo > dir > bdo.
    let b3 = make_docx(
        r#"<w:p><w:bdo w:val="rtl"><w:dir w:val="ltr"><w:bdo w:val="rtl"><w:r><w:t>Q</w:t></w:r></w:bdo></w:dir></w:bdo></w:p><w:sectPr/>"#,
        &[],
    );
    assert!(
        reserialize(&b3).contains(
            r#"<w:bdo w:val="rtl"><w:dir w:val="ltr"><w:bdo w:val="rtl"><w:r><w:t>Q</w:t></w:r></w:bdo></w:dir></w:bdo>"#
        ),
        "deep bdo>dir>bdo nesting must round-trip verbatim: {}",
        reserialize(&b3)
    );
    assert_eq!(accept_text(&b3), "Q");
}

// ─── Run-level content inside bdo/dir (EG_PContent in CT_BdoContentRun) ───────
// A `w:bdo`/`w:dir` direction wrapper is a transparent container over
// EG_PContent, so it may legally hold — between/around its runs — the same
// zero-width run-level markup (EG_RunLevelElts) a paragraph may: proofErr,
// bookmarks, permStart/End, comment ranges, move ranges, … Word authors and
// opens these clean; import must preserve them in place through the wrapper.

/// Pack a body + a footnotes part into a minimal DOCX (mirrors the body-only
/// `make_docx`; the footnotes part gets its canonical content-type override and
/// a relationship so it is discovered as a story).
fn make_docx_with_footnotes(body_xml: &str, footnotes_xml: &str) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );
    let content_types = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/><Override PartName="/word/footnotes.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.footnotes+xml"/></Types>"#;
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId10" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/footnotes" Target="footnotes.xml"/></Relationships>"#;

    let mut buf = Vec::new();
    {
        use zip::write::FileOptions;
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        zip.start_file("word/footnotes.xml", opts).unwrap();
        zip.write_all(footnotes_xml.as_bytes()).unwrap();
        zip.finish().unwrap();
    }
    buf
}

/// Concatenate the `Normal`-status text of every paragraph in a footnote story.
fn footnote_story_text(bytes: &[u8], note_id: &str) -> String {
    use stemma::domain::{BlockNode, InlineNode};
    let doc = Document::parse(bytes).expect("parse doc with footnote story");
    let canon = doc.snapshot().canonical.clone();
    let story = canon
        .footnotes
        .iter()
        .find(|f| f.id == note_id)
        .unwrap_or_else(|| panic!("footnote story {note_id} present"));
    let mut out = String::new();
    for tb in &story.blocks {
        if let BlockNode::Paragraph(p) = &tb.block {
            for inline in p.segments.iter().flat_map(|s| s.inlines.iter()) {
                if let InlineNode::Text(t) = inline {
                    out.push_str(&t.text);
                }
            }
        }
    }
    out
}

/// §17.3.2.3 (CT_BdoContentRun → EG_PContent → EG_RunLevelElts): a `w:proofErr`
/// proofing marker sitting BETWEEN the runs inside a `w:bdo` is legal content
/// (this is the exact shape a real Word-authored document carried). Import must
/// accept it, read the wrapped text through the display-only wrapper, and
/// round-trip the markers in place inside the re-nested `w:bdo`.
#[test]
fn bdo_preserves_run_level_prooferr_between_runs() {
    let body = r#"<w:p><w:bdo w:val="rtl"><w:r><w:t>abc</w:t></w:r><w:proofErr w:type="spellStart"/><w:r><w:t>def</w:t></w:r><w:proofErr w:type="spellEnd"/></w:bdo></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    // Import succeeds; the display-only wrapper contributes its inner logical
    // text, and proofErr (zero-width) adds nothing.
    assert_eq!(
        accept_text(&b),
        "abcdef",
        "§17.3.2.3: bdo is display-only; the wrapped runs read through as logical text, and proofErr is zero-width."
    );
    assert_eq!(
        reject_text(&b),
        "abcdef",
        "§17.3.2.3: bdo carries no revision; reject reproduces the same logical text as accept."
    );

    // Opens clean — proofErr inside bdo is schema-valid EG_RunLevelElts content.
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "§17.3.2.3 (CT_BdoContentRun) + §17.13.5 (proofErr is EG_RunLevelElts): a proofErr between runs inside bdo is schema-valid; Word opens it without repair. validate issues: {detail}"
    );

    // Round-trip: both proofErr markers survive INSIDE the re-nested bdo, in
    // their original positions relative to the runs (the serializer's renest
    // pass folds the intervening siblings back inside the wrapper).
    let xml = reserialize(&b);
    assert!(
        xml.contains(
            r#"<w:bdo w:val="rtl"><w:r><w:t>abc</w:t></w:r><w:proofErr w:type="spellStart"/><w:r><w:t>def</w:t></w:r><w:proofErr w:type="spellEnd"/></w:bdo>"#
        ),
        "§17.3.2.3: the proofErr markers must round-trip INSIDE the re-nested bdo, between/after the runs, not be dropped or hoisted out. document.xml:\n{xml}"
    );
}

/// §17.3.2.3: run-level markup inside a bdo must survive a tracked edit made
/// ELSEWHERE in the document (the model-rebuild serializer path), and the
/// redline must retain accept/reject identity — accept-all yields the target
/// text, reject-all the base — with the untouched bdo (and its proofErr) intact.
#[test]
fn bdo_run_level_markup_survives_tracked_edit_elsewhere() {
    use stemma::{DocxRuntime, ExportMode, SimpleRuntime, TransactionMeta};
    let bdo_para = r#"<w:p><w:bdo w:val="rtl"><w:r><w:t>abc</w:t></w:r><w:proofErr w:type="spellStart"/><w:r><w:t>def</w:t></w:r><w:proofErr w:type="spellEnd"/></w:bdo></w:p>"#;
    let before = make_docx(
        &format!("{bdo_para}<w:p><w:r><w:t>edit me</w:t></w:r></w:p><w:sectPr/>"),
        &[],
    );
    let after = make_docx(
        &format!("{bdo_para}<w:p><w:r><w:t>edited!</w:t></w:r></w:p><w:sectPr/>"),
        &[],
    );
    let rt = SimpleRuntime::new();
    let ib = rt.import_docx(&before).expect("import before");
    let ia = rt.import_docx(&after).expect("import after");
    let meta = TransactionMeta {
        author: "bidi-spec".into(),
        reason: None,
        timestamp_utc: Some("2025-01-15T10:30:00Z".into()),
    };
    let applied = rt
        .diff_and_redline(&ib.doc_handle, &ia.doc_handle, meta)
        .expect("diff_and_redline");
    assert!(applied.applied, "the text edit should produce a redline");
    let out = rt
        .export_docx(&ib.doc_handle, ExportMode::Redline)
        .expect("export redline");

    // Accept-all == target, reject-all == base; the untouched bdo text reads
    // through on both sides.
    let acc = accept_text(&out);
    let rej = reject_text(&out);
    assert!(
        acc.contains("abcdef") && acc.contains("edited!") && !acc.contains("edit me"),
        "accept-all must yield the target: bdo text through + the edited paragraph. accept text: {acc:?}"
    );
    assert!(
        rej.contains("abcdef") && rej.contains("edit me") && !rej.contains("edited!"),
        "reject-all must yield the base: bdo text through + the original paragraph. reject text: {rej:?}"
    );

    // The bdo re-nested to a single element and both proofErr markers survived.
    let xml = document_xml_of(&out);
    assert_eq!(
        xml.matches("<w:bdo").count(),
        1,
        "the untouched bdo must re-nest into one element on the rebuild path. document.xml:\n{xml}"
    );
    assert_eq!(
        xml.matches("<w:proofErr").count(),
        2,
        "both proofErr markers inside the bdo must survive the rebuild. document.xml:\n{xml}"
    );
}

/// §17.3.2.3 (footnotes story): the wild witness carried `proofErr` inside a
/// `w:bdo` in word/footnotes.xml. The story import path must behave identically
/// to the body path — import succeeds and the wrapped text reads through.
#[test]
fn bdo_run_level_markup_in_footnote_story_imports() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Body</w:t></w:r><w:r><w:rPr><w:rStyle w:val="FootnoteReference"/></w:rPr><w:footnoteReference w:id="1"/></w:r></w:p><w:sectPr/>"#;
    let footnotes = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:footnotes xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:footnote w:type="separator" w:id="-1"><w:p><w:r><w:separator/></w:r></w:p></w:footnote><w:footnote w:type="continuationSeparator" w:id="0"><w:p><w:r><w:continuationSeparator/></w:r></w:p></w:footnote><w:footnote w:id="1"><w:p><w:r><w:footnoteRef/></w:r><w:bdo w:val="rtl"><w:r><w:t>abc</w:t></w:r><w:proofErr w:type="spellStart"/><w:r><w:t>def</w:t></w:r><w:proofErr w:type="spellEnd"/></w:bdo></w:p></w:footnote></w:footnotes>"#;
    let b = make_docx_with_footnotes(body, footnotes);

    // Import must not fail with "unknown run-level element: proofErr" (the bug).
    assert!(
        Document::parse(&b).is_ok(),
        "§17.3.2.3: proofErr inside a w:bdo in a footnote story is legal EG_RunLevelElts content; the story import path must accept it, not fail loud."
    );
    // The wrapped text reads through in the story exactly as in the body.
    assert_eq!(
        footnote_story_text(&b, "1"),
        "abcdef",
        "the bdo-wrapped runs in the footnote story must read through as logical text (proofErr is zero-width)."
    );
}

/// §17.3.2.8 (CT_DirContentRun → EG_PContent): a bookmarkStart/bookmarkEnd pair
/// is another zero-width run-level decoration class legal inside a `w:dir`. Both
/// halves of the pair must round-trip inside the re-nested wrapper (tearing the
/// pair would leave a dangling bookmark Word would repair).
#[test]
fn dir_preserves_bookmark_pair_around_run() {
    let body = r#"<w:p><w:dir w:val="rtl"><w:bookmarkStart w:id="0" w:name="anchor"/><w:r><w:t>marked</w:t></w:r><w:bookmarkEnd w:id="0"/></w:dir></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b),
        "marked",
        "§17.3.2.8: dir is display-only; the wrapped run reads through and the bookmark markers are zero-width."
    );
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "§17.3.2.8 (CT_DirContentRun) + §17.13.6 (bookmarks are EG_RangeMarkupElements): a bookmark pair inside dir is schema-valid; Word opens it without repair. validate issues: {detail}"
    );
    let xml = reserialize(&b);
    assert!(
        xml.contains(
            r#"<w:dir w:val="rtl"><w:bookmarkStart w:id="0" w:name="anchor"/><w:r><w:t>marked</w:t></w:r><w:bookmarkEnd w:id="0"/></w:dir>"#
        ),
        "§17.3.2.8: BOTH bookmark halves must round-trip inside the re-nested dir, keeping the pair intact. document.xml:\n{xml}"
    );
}

/// §17.3.2.3: a `w:hyperlink` inside a `w:bdo` is deliberately kept FAIL-LOUD.
/// The paragraph path models a hyperlink as a space-occupying barrier atom, but
/// the wrapper's serializer re-nest pass folds intervening zero-width-or-text
/// siblings back inside the wrapper and is not built to re-nest a barrier atom;
/// descending would need that pass restructured. Rather than silently drop the
/// hyperlink (CLAUDE.md: no silent fallbacks) import refuses with the existing
/// `UnknownRunElement` error. This test pins that behavior as intentional.
#[test]
fn hyperlink_inside_bdo_fails_loud_not_silent_drop() {
    let body = r#"<w:p><w:bdo w:val="rtl"><w:hyperlink w:anchor="target"><w:r><w:t>link</w:t></w:r></w:hyperlink></w:bdo></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let parsed = Document::parse(&b);
    assert!(
        parsed.is_err(),
        "a hyperlink inside a bdo wrapper must fail loud, not silently drop the link content"
    );
    let msg = format!("{:?}", parsed.err().unwrap());
    assert!(
        msg.contains("unknown run-level element") && msg.contains("hyperlink"),
        "the refusal must name the unhandled run-level element (hyperlink), not panic or drop it silently. error: {msg}"
    );
}
